const express = require('express');
const app = express();
app.use(express.urlencoded({ extended: true }));
app.use(express.json());

const codes = {};

async function generateRandomString() {
    return Math.random().toString(36).substr(2, 10);
}

function findUserByConsent(userConsents) {
    for (const consent of userConsents) {
        if (consent.user.id === '1') {
            return { id: '1', email: 'user@example.com' };
        }
    }
    return null;
}

app.get('/authorize', async (req, res) => {
    const clientId = req.query.client_id;
    const redirectUri = req.query.redirect_uri;
    if (!clientId || !redirectUri) {
        return res.status(400).json({ error: 'client id or redirect uri missing' });
    }
    const userConsents = { user: { id: '1', email: 'user@example.com' } };
    const user = findUserByConsent(userConsents);
    if (!user) {
        return res.status(401).json({ error: 'unauthorized access' });
    }

    const code = await generateRandomString();
    codes[code] = { clientId, redirectUri, scope: req.query.scope, user };
    const params = `?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=code&scope=${req.query.scope}&code=${code}`;
    res.redirect(params);
});

app.post('/token', async (req, res) => {
    const code = req.body.code;
    if (!codes[code]) {
        return res.status(401).json({ error: 'invalid authorization code' });
    }
    const { clientId, redirectUri, scope } = codes[code];
    delete codes[code];

    if (redirectUri !== req.body.redirect_uri) {
        return res.status(400).json({ error: 'mismatching redirect uri' });
    }

    // todo: implement client credentials flow for token refresh

    const accessToken = await generateRandomString();
    const refreshToken = await generateRandomString();
    res.json({
        access_token: accessToken,
        token_type: 'Bearer',
        expires_in: 3600,
        scope
    });
});

app.listen(3001, () => {
    console.log('Authorization server listening on port 3001');
});